      if (window.onFlutterNotification) {
        window.onFlutterNotification(${jsonEncode(message.data)});
      }
    ''';
    _controller.runJavaScript(script);
  }

  void _handleNotificationTap(RemoteMessage message) {
    String script = '''
      if (window.onFlutterNotificationTap) {
        window.onFlutterNotificationTap(${jsonEncode(message.data)});
      }
    ''';
    _controller.runJavaScript(script);
  }

  Future<void> _openCamera() async {
    try {
      final XFile? photo = await _imagePicker.pickImage(
        source: ImageSource.camera,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (photo != null) {
        final bytes = await photo.readAsBytes();
        final base64Image = base64Encode(bytes);
        
        String script = '''
          if (window.onCameraResult) {
            window.onCameraResult({
              path: "${photo.path}",
              name: "${photo.name}",
              base64: "$base64Image"
            });
          }
        ''';
        await _controller.runJavaScript(script);
      } else {
        String script = '''
          if (window.onCameraResult) {
            window.onCameraResult(null);
